import{_ as i,c as a,a as e,o as n}from"./app-CEcM0piI.js";const s={};function o(r,l){return n(),a("div",null,l[0]||(l[0]=[e('<ol><li>BigInt js自带</li><li>Decimal 库</li></ol><h1 id="大文件上传" tabindex="-1"><a class="header-anchor" href="#大文件上传"><span>大文件上传</span></a></h1><p>场景：</p><ol><li>ai自定义模型</li><li>长视频网站</li><li>建模网站</li></ol><p>需求： 3. 断点续传 4. 断开重传 5. 切片上传</p><p>方案：</p><ol><li>分片，切片取名：hash+index，后端组合切片</li><li>切片时主线程卡顿：web-worker多线程切片</li><li>切片完后将blob存储到IndexedDB，下次用户进来后嗅探一下是否有未上传完的切片</li><li>上传完毕后使用websocker通知</li></ol><h1 id="截图" tabindex="-1"><a class="header-anchor" href="#截图"><span>截图</span></a></h1><ol><li>canvans</li><li>puppeteer</li><li>html2canvas</li></ol><h1 id="移动端适配" tabindex="-1"><a class="header-anchor" href="#移动端适配"><span>移动端适配</span></a></h1><ol><li>不同端使用不同的网址</li><li>根据不同端加载不同的css</li><li>使用响应式（媒体查询）</li></ol><h1 id="水印功能" tabindex="-1"><a class="header-anchor" href="#水印功能"><span>水印功能</span></a></h1><ol><li>明水印（肉眼可见） 使用Canvas或css设置中背景图片水印。 svg动态水印</li><li>暗水印（肉眼不可见） 将水印内容写入到到二进制文件，读取时从文件中读取</li></ol><h1 id="静态资源失效" tabindex="-1"><a class="header-anchor" href="#静态资源失效"><span>静态资源失效</span></a></h1><ol><li>图片 占位图或out，图片失效时显示 重试、上报</li><li>sss 重要的样式使用html内联的写法。</li><li>cdn 本地备份，动态切换.</li><li>字体 降低字体（兜底）.</li></ol><h1 id="函数式编程" tabindex="-1"><a class="header-anchor" href="#函数式编程"><span>函数式编程</span></a></h1><p>以函数封装的方式解决问题，将大问题拆方为多个小问题。 设计函数用于解决小问题，最后通过组合的方式解决问题</p><ol><li>纯函数：相同输入得到相可输出</li><li>不可变性</li><li>高阶函数（函数柯里化）</li></ol><p>优点：</p><ol><li>可测试性（更好地单元测试）</li><li>可维护性（组合优于继承）</li><li>并发和简洁</li></ol><h1 id="图片加载性能优化" tabindex="-1"><a class="header-anchor" href="#图片加载性能优化"><span>图片加载性能优化</span></a></h1><ol><li>懒加载 在html中将图片的src属性更改为自定义的属性，这样浏览器遇到这个属性时就不会像默认的属性进行处理，当需要加载时将自定义属性的值赋值给src属性</li></ol><p>获取到图片的dom，添加监听滚动事件，判断自身与视口的距离，达到一定距离就加载图片 这种方法的缺点是：不停的监听滚动事件，即使已经加载了图片，还是不断地触发事件，性能开销大 IntersectionObserver观察dom元素可视口的交叉区域，每次视口进入dom的显示区域都会调用回调函数。当图片加载后取消观察。</p><ol start="2"><li>上拉加载和下拉刷新 监听滚动事件如果新的视口和原视口位置有一定的距离就请求数据并添加到数据列表中 监听触摸事件，下划的矩离与原距离有一定距离就请空教据列表并将请求的数据添加的到表中 同时也要实现书流，防抖</li></ol><h1 id="seo优化" tabindex="-1"><a class="header-anchor" href="#seo优化"><span>SEO优化</span></a></h1><ol><li>使用语义化标签（便于爬虫区分信息）</li><li>标题和描述内容</li><li>内容优化，关键词覆盖</li><li>技术向，站点地图告诉爬虫站点内容（Robot.txt）</li></ol><h1 id="防抖和节流" tabindex="-1"><a class="header-anchor" href="#防抖和节流"><span>防抖和节流</span></a></h1><h2 id="节流" tabindex="-1"><a class="header-anchor" href="#节流"><span>节流</span></a></h2><p>为防止一个事件短时间内的重复触发一般在开始执行任务的时候设置一个时间间隔，在这个时间间隔内再次触发此任务将不会执行</p><h2 id="防抖" tabindex="-1"><a class="header-anchor" href="#防抖"><span>防抖</span></a></h2><p>当一个事件触发时设置一个计时器，在计时器计时的时间内再次触发这个事件将重置计时且不会执行，只有计时器计时结束才触发事件</p><h1 id="页面加载优化" tabindex="-1"><a class="header-anchor" href="#页面加载优化"><span>页面加载优化</span></a></h1><p>**代码优化</p><ul><li>减少HTTP请求：合并文件、使用雪碧图、压缩资源。</li><li>优化代码结构：避免重复代码，使用函数和组件提高复用性。</li><li>懒加载：延迟加载非首屏资源，如图片、视频、组件。</li></ul><p><strong>资源优化</strong></p><ul><li>压缩资源：使用Gzip等压缩算法减小文件体积。</li><li>缓存资源：利用浏览器缓存，减少重复下载。</li><li>使用CDN：加速资源加载。</li></ul><p><strong>渲染优化</strong></p><ul><li>减少重排和重绘：避免频繁操作DOM，使用<code>DocumentFragment</code>或虚拟DOM。</li><li>使用异步加载：如<code>async</code>和<code>defer</code>加载脚本，不影响页面渲染。</li><li>服务端渲染（SSR）：减少首屏加载时间，提升用户体验。</li></ul><h1 id="预加载和懒加载的区别" tabindex="-1"><a class="header-anchor" href="#预加载和懒加载的区别"><span>预加载和懒加载的区别</span></a></h1><p><strong>预加载</strong></p><ul><li>定义：在页面加载时或用户操作前，提前加载可能需要的资源。</li><li>优点：减少用户等待时间，提升体验。</li><li>缺点：增加初始加载时间，可能加载无用资源。</li></ul><p><strong>懒加载</strong></p><ul><li>定义：延迟加载非首屏或暂时不需要的资源，在需要时再加载。</li><li>优点：减少初始加载时间，优化性能。</li><li>缺点：可能增加用户等待时间，需要合理控制加载时机。</li></ul>',43)]))}const h=i(s,[["render",o]]),p=JSON.parse('{"path":"/front/interview/2/","title":"2. 场景题","lang":"zh-CN","frontmatter":{"title":"2. 场景题","createTime":"2025/06/17 18:12:26","permalink":"/front/interview/2/"},"readingTime":{"minutes":4.06,"words":1219},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/面经/2. 场景题.md","headers":[]}');export{h as comp,p as data};
